#include <bits/stdc++.h>
using namespace std;
int n,k,a[2000006];
int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    deque<int> q;
    for(int i=1;i<=n;i++){
        while(q.size() && q.front()<=i-k)
            q.pop_front();
        while(q.size() && a[q.back()]<=a[i])
            q.pop_back();
        q.push_back(i);
        if(i>=k)
            printf("%d\n",a[q.front()]);
    }
    return 0;
}
